import { t as private_env } from "../chunks/shared-server.js";
import { t as api } from "../chunks/api.js";
import { sequence } from "@sveltejs/kit/hooks";
import fs from "node:fs";
import path from "node:path";
import crypto from "node:crypto";
//#region src/hooks.server.ts
if (!private_env.ENCRYPTION_KEY) {
	const keyFile = path.resolve(".encryption-key");
	let key;
	if (fs.existsSync(keyFile)) key = fs.readFileSync(keyFile, "utf8").trim();
	else {
		key = crypto.randomBytes(32).toString("hex");
		fs.writeFileSync(keyFile, key, "utf8");
		console.log("[hooks] Generated ENCRYPTION_KEY and saved to .encryption-key");
	}
	process.env.ENCRYPTION_KEY = key;
}
var handle = sequence(api);
//#endregion
export { handle };
